const { randomUUID } = require('crypto');
const Autumn = require('autumn-js');

const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

/**
 * Generate AI completion with budget control using Autumn's balance locking pattern
 * @param {string} customerId - Customer identifier
 * @param {number} maxTokens - Maximum tokens to reserve
 * @returns {Promise<{lockId: string, tokensUsed: number, confirmed: boolean}>}
 */
async function generateWithBudget(customerId, maxTokens) {
  // Step 1: Generate a unique lockId
  const lockId = `completion_${randomUUID()}`;

  try {
    // Step 2: Check and lock the balance
    const checkResult = await autumn.customers.check({
      customerId,
      featureId: 'ai-tokens',
      requiredBalance: maxTokens,
      sendEvent: true,
      lock: {
        enabled: true,
        lockId,
        expiresAt: Date.now() + 60000
      }
    });

    // Step 3: If not allowed, throw error
    if (!checkResult.allowed) {
      throw new Error('Insufficient ai-tokens balance');
    }

    // Step 4: Simulate AI work
    await new Promise(resolve => setTimeout(resolve, 100));
    const tokensUsed = Math.floor(maxTokens * 0.75);

    // Step 5: Finalize the lock by confirming with actual usage
    await autumn.balances.finalize({
      lockId,
      action: 'confirm',
      overrideValue: tokensUsed
    });

    // Step 6: Return result
    return {
      lockId,
      tokensUsed,
      confirmed: true
    };
  } catch (error) {
    // Step 7: On error, release the lock and re-throw
    try {
      await autumn.balances.finalize({
        lockId,
        action: 'release'
      });
    } catch (releaseError) {
      // Log release error but don't mask the original error
      console.error('Failed to release lock:', releaseError.message);
    }
    throw error;
  }
}

module.exports = {
  generateWithBudget
};

